INSERT INTO public.noticias (id, titulo, conteudo, tipo, departamento, publicado_por, publicado, data_publicacao, created_at, updated_at, categoria, visibilidade, imagem_url, autor_nome, autor_id) VALUES (7, 'Sem nada', '.news-list {
  display: flex;
  flex-direction: column;
  gap: 48px;
  max-width: 860px;
  margin: 0 auto;
}

.public-news-card-full {
  background: #fff;
  border-radius: 16px;
  border: 1px solid #eee;
  box-shadow: 0 10px 40px rgba(0,0,0,0.05);
  overflow: hidden;
  transition: 0.3s ease;
}

.public-news-card-full:hover {
  box-shadow: 0 15px 50px rgba(0,0,0,0.1);
}

.card-img-full {
  width: 100%;
}

.card-img-full img {
  width: 100%;
  max-height: 480px;
  object-fit: cover;
  display: block;
}

.card-body-full {
  padding: 28px 32px 32px;
  display: flex;
  flex-direction: column;
}

.card-body-full h3 {
  font-size: 1.4rem;
  color: #111;
  margin: 12px 0 16px;
  font-weight: 700;
}

.card-body-full p {
  color: #444;
  font-size: 14px;
  line-height: 1.8;
  margin: 0 0 20px;
  white-space: pre-wrap;
}', NULL, 'todos', NULL, true, '2026-05-26 00:31:33.5307', '2026-05-26 00:31:33.5307', '2026-05-26 00:31:33.5307', 'aviso', 'publica', NULL, 'José Gean De Macedo Alves', 11);
